  "preconditions": [
    "x must be a real number",
    "x must be in the range [-1, 1]"
  ],
  "postconditions": [
    "returns the arc sine (measured in radians) of x",
    "returns a real number in the range [-π/2, π/2]"
  ],
  "edge_cases": [
    "x = -1 returns -π/2",
    "x = 1 returns π/2",
    "x = 0 returns 0"
  ]
}

